+    /// Augmented Lagrangian penalty helper for inequality constraints g_i(x) <= 0.
+    pub fn augmented_lagrangian_penalty_raw(g: &[f64], lambda: &[f64], rho: f64) -> f64 {
+        let mut pen = 0.0;
+        for (gi, li) in g.iter().zip(lambda.iter()) {
+            let pos = gi.max(0.0);
+            pen += li * pos + 0.5 * rho * pos * pos;
+        }
